  .next-action-item__delete-button {
    background: none;
    border: none;
    padding: var(--space-xs);
    cursor: pointer;
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    border-radius: var(--radius-sm);
  }

  .next-action-item__delete-button:hover {
    background: none;
    color: var(--color-danger);
  }

  /* Next action edit form */
  .next-action-item__edit-form {
    flex: 1;
    display: flex;
    align-items: center;
    gap: var(--space-xs);
    min-inline-size: 0;
  }

  .next-action-item__edit-input {
    flex: 1;
