    await page
      .getByRole("button", { name: /Mark .+Buy groceries.+ as complete/ })
      .click();

    // After toggling, the page should still show the todo
    // (either via HTMX swap or page reload)
    await expect(page.getByText("Buy groceries")).toBeVisible();

